+/* Glass Card - The "Stripe" Feel */
+.glass-card {
+  @apply bg-slate-900/40 backdrop-blur-xl border border-white/5 rounded-3xl shadow-glass transition-all duration-500 relative overflow-hidden;
+}
+.glass-card::before {
+  content: "";
+  @apply absolute inset-0 bg-gradient-surface opacity-0 transition-opacity duration-500;
+}
+.glass-card:hover {
+  @apply border-white/10 shadow-glow-sm transform -translate-y-[1px];
+}
+.glass-card:hover::before {
+  @apply opacity-100;
+}
+
+/* Range Inputs - Slick & Tactile */
+input[type="range"] {
+  @apply appearance-none bg-transparent cursor-pointer w-full h-8 touch-none; /* Larger touch target height */
+}
+input[type="range"]:focus {
+  @apply outline-none;
+}
+
+/* Track */
+input[type="range"]::-webkit-slider-runnable-track {
+  @apply h-1.5 w-full rounded-full bg-slate-800 shadow-inner border border-white/5 transition-colors duration-300;
+}
+input[type="range"]:hover::-webkit-slider-runnable-track {
+  @apply bg-slate-700;
+}
+input[type="range"]::-moz-range-track {
+  @apply h-1.5 w-full rounded-full bg-slate-800 shadow-inner border border-white/5 transition-colors duration-300;
+}
+
+/* Thumb - Larger & animated */
+input[type="range"]::-webkit-slider-thumb {
+  @apply appearance-none h-5 w-5 rounded-full bg-white shadow-lg border border-slate-300 -mt-[7px] transition-transform duration-200;
+}
+input[type="range"]:active::-webkit-slider-thumb {
+  @apply scale-125 border-sky-400 bg-sky-50 shadow-glow-sm;
+}
+input[type="range"]::-moz-range-thumb {
+  @apply appearance-none h-5 w-5 rounded-full bg-white shadow-lg border border-slate-300 border-none transition-transform duration-200;
+}
+input[type="range"]:active::-moz-range-thumb {
+  @apply scale-125 border-sky-400 bg-sky-50 shadow-glow-sm;
+}
+
+/* Custom Scrollbar */
+::-webkit-scrollbar {
+  width: 10px;
+  height: 10px;
+}
+::-webkit-scrollbar-track {
+  background: #020617;
+}
+::-webkit-scrollbar-thumb {
+  background: #334155;
+  border-radius: 5px;
+  border: 2px solid #020617; /* Padding effect */
 }
+::-webkit-scrollbar-thumb:hover {
+  background: #475569;
+}
